import{_ as r,o as t,c as p,j as e,a as n,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"魔力机关枢纽-伪象命匣","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/2.改造与功法/改造/6.一次性改造/魔力机关枢纽-伪象命匣.md","filePath":"4.资源分区/2.改造与功法/改造/6.一次性改造/魔力机关枢纽-伪象命匣.md"}'),_={name:"4.资源分区/2.改造与功法/改造/6.一次性改造/魔力机关枢纽-伪象命匣.md"};function o(d,a,l,i,c,h){return t(),p("div",null,[...a[0]||(a[0]=[e("h1",{id:"魔力机关枢纽-伪象命匣",tabindex:"-1"},[n("魔力机关枢纽-伪象命匣 "),e("a",{class:"header-anchor",href:"#魔力机关枢纽-伪象命匣","aria-label":'Permalink to "魔力机关枢纽-伪象命匣"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：绯红庆典040")])])],-1),s('<h1 id="魔力机关枢纽-伪象命匣-1" tabindex="-1">魔力机关枢纽-伪象命匣 <a class="header-anchor" href="#魔力机关枢纽-伪象命匣-1" aria-label="Permalink to &quot;魔力机关枢纽-伪象命匣&quot;">​</a></h1><p>魔力机关枢纽-伪象命匣<br> 魔幻本质<br> 一次性改造<br> B+2400<br> 前置：具有魔力或变体魔力能量池<br> 描述：<br> 巫妖的不死性源于他们的命匣，装载着他们灵魂与心脏，只要命匣还存在，通过各种手段就可以将本体拉回现世。</p><p>但，命匣的产生需要心脏这一生命枢纽，这意味着似乎成为不死生物才能取得这种手段。</p><p>大魔导师将其作为自己的终生课题研究，得出了一个想法：</p><p>如果以魔力源流作为能量，魔力机关代替心脏泵动的话...</p><p>以人之身，成为不朽存在，并非不可能。</p><p>效果：<br> 一枚与心脏灵魂相连的方形魔力枢纽机关现在替换了你原本的心脏部位，替代了你心脏原本的功能，而你的心脏则被亲爱的主神收走，制作成了命匣。</p><p>当你在影片死去时，远在主神空间的心脏将不断泵动，通过枢纽机关重新唤醒你远在影片内的躯体，由于连接需要超越各种时空，需要经过至少72天后才能连接复活。在此期间枢纽机关的结构值为你的生命值上限，如果机关被摧毁，你就因为无法连接主神空间的心脏而复活。</p><p>在该过程中你的灵魂以灵体形式存在，除了观察和移动外无法进行更多的动作，这是一个B级时空来源的复活效果。</p><p>作为以魔力作为能源的枢纽机关，自然存在主动强化的能力，以一个自由动作，消耗9点魔力或变体魔力激活魔力机关枢纽-伪象命匣，本场景内你进入魔力枢纽过载状态。</p><p>魔力枢纽过载状态下持有者获得以下效果：</p><p>1.庞大的魔力流使你的魔力循环更加迅速，每回合你获得4AP使用法术，这些AP的使用需要遵循攻击技-应对技-防御技-攻击技艺-…的循环，若将这些AP用在循环之外的法术施展上，本场战斗将不再获得这些AP。<br> （例如，轮回者芭芭雅嘎对敌人施展了扭蛋术，这是一个攻击技，意味着她下回合必须要将这些AP投入到应对技中，否则下下个回合将无法获得这些AP）</p><p>2.你的施法更具力量，你在施法检定上获得等同于你智力属性的器械加值。</p><p>2.魔力强行维持着你的身躯，你获得2点快速医疗（医疗点24）</p><p>3.以不同的咏唱调度，共鸣出更强的法术力量，你获得仅对释放法术生效的【激昂】，但该【激昂】提供的加值类型为器械加值而非技艺加值。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',17)])])}const P=r(_,[["render",o]]);export{f as __pageData,P as default};
